#!/usr/bin/env node
/**
 * Build downloadable EVVM packages — one zip per EIP demo.
 *
 * Reads `content/demos/<slug>/` and produces
 * `public/downloads/<slug>.zip` containing:
 *
 *   <slug>/
 *   ├── README.md          (auto-generated install/usage guide)
 *   ├── manifest.json      (copied as-is)
 *   ├── justification.md   (copied as-is)
 *   └── contracts/*.sol    (copied as-is)
 *
 * Uses the system `zip` command. Vercel build env (Ubuntu) ships it.
 * No npm deps. Run via `pnpm build:packages` or implicitly via
 * the `prebuild` lifecycle hook in package.json.
 */

import { execSync } from "node:child_process";
import {
  readdirSync,
  statSync,
  mkdirSync,
  writeFileSync,
  rmSync,
  cpSync,
  readFileSync,
} from "node:fs";
import { join } from "node:path";

const ROOT = process.cwd();
const CONTENT_DIR = join(ROOT, "content", "demos");
const OUT_DIR = join(ROOT, "public", "downloads");
const STAGE_DIR = join(ROOT, ".build-staging");

function generateReadme(slug, manifest) {
  const m = manifest.eip;
  const e = manifest.experiment;
  const contractList = (manifest.contracts ?? [])
    .map((c) => `- \`${c.path}\` — _${c.type}_`)
    .join("\n");

  return `# EVVM Package — EIP-${m.number}: ${m.title}

Generated by [EIPLab](https://github.com/0xOucan/eiplabv1) for use with
[scaffold-evvm](https://github.com/EVVM-org/scaffold-evvm).

| | |
|---|---|
| **EIP** | [EIP-${m.number}](${m.url}) |
| **Status** | ${m.status} |
| **Shape** | ${e.shape} |
| **Slug** | \`${e.slug}\` |

## ⚠ Read this first

Before doing anything with these contracts:

1. Read **\`NEXT_STEPS.md\`** in this folder — it walks you through
   reading the EVVM documentation and using scaffold-evvm for local
   testing BEFORE any deployment.
2. Read **\`justification.md\`** — it explains every contract, every
   mock's limitation, and what claims this experiment does and does
   not support.

## Hypothesis

${e.hypothesis}

## What's in this package

\`\`\`
${slug}/
├── README.md         (this file)
├── NEXT_STEPS.md     (EVVM docs + local-testing guide — read first)
├── manifest.json     (dependencies, mocks, contracts index)
├── justification.md  (per-contract writeup — what, why, limitations)
└── contracts/        (the Solidity files)
\`\`\`

### Contracts

${contractList || "_(none)_"}

## Quick start

\`\`\`bash
# 1. Clone scaffold-evvm if you don't have it yet
git clone git@github.com:EVVM-org/scaffold-evvm.git
cd scaffold-evvm

# 2. Drop this folder into experiments/
mkdir -p experiments
cp -r /path/to/${slug} experiments/

# 3. Start the local EVVM stack via the wizard
npm install
npm run wizard

# 4. Continue per NEXT_STEPS.md
\`\`\`

The contracts in this package were produced by EIPLab's minimal-skill
workflow: modify the core, add services, mock the heavy crypto, write
a per-contract justification. Tests, deploys, and EIP drafts are
intentionally **not** included — use your own tooling for those.

## License

EVVM Noncommercial License v1.0 — see
https://www.evvm.info/docs/EVVMNoncommercialLicense
`;
}

function generateNextSteps(slug, manifest) {
  const m = manifest.eip;
  const e = manifest.experiment;

  return `# Next Steps — EIP-${m.number} EVVM Package

You've downloaded an EVVM package generated by
[EIPLab](https://github.com/0xOucan/eiplabv1). This file is your
recommended path from "I have the .sol files" to "I know whether
this EIP holds up on EVVM."

## 1. Read the EVVM documentation FIRST

Before modifying or running anything, get familiar with the EVVM
protocol surface this experiment touches:

- **scaffold-evvm overview** — the local testing environment:
  https://www.evvm.info/docs/LibrariesAndTools/ScaffoldEvvm/Overview
- **Core contract reference** — the contract most EIPs touch:
  https://www.evvm.info/docs/category/coresol
- **How to make an EVVM service** — pattern for new-service experiments:
  https://www.evvm.info/docs/HowToMakeAEVVMService
- **NameService, Staking, Treasury references** — relevant when an
  experiment modifies one of these:
  - https://www.evvm.info/docs/category/nameservicesol
  - https://www.evvm.info/docs/category/staking-contracts
  - https://www.evvm.info/docs/category/treasury

The contracts in this package are designed to drop into scaffold-evvm's
\`experiments/\` folder. Knowing the canonical contracts they're
forked from will save you a lot of debugging time later.

## 2. Use scaffold-evvm for local testing — BEFORE any deploy

scaffold-evvm runs the full EVVM stack on Anvil or Hardhat Network
locally. It is the recommended environment for iterating on this
experiment because:

- **Free** — no testnet ETH needed
- **Fast** — no block times to wait for
- **Resettable** — \`npm run cli flush\` wipes state in seconds
- **Mock-friendly** — \`vm.etch\` lets you plant system contracts at
  fixed addresses, which is critical for several of the mocks in
  this package

\`\`\`bash
git clone git@github.com:EVVM-org/scaffold-evvm.git
cd scaffold-evvm
mkdir -p experiments
cp -r /path/to/${slug} experiments/
npm install
npm run wizard
\`\`\`

Then run your own Foundry / Hardhat test suite against the deployed
local stack. The shape of the suite is up to you — this package
ships **no tests** by design.

## 3. Read justification.md and the mock limitations

Every mock contract in this package has an explicit \`limitation\`
field in \`manifest.json\` AND a corresponding section in
\`justification.md\`. Common categories:

- **Mock ZK verifiers** (e.g. Groth16 stubs) have **NO cryptographic
  security** — only useful for state-machine tests.
- **Mock hash functions** (e.g. MockPoseidon) are usually keccak-based
  with matched domain separators — **NOT collision-equivalent** to
  real Poseidon. Circuit-generated values will not match.
- **Mock opcodes** (e.g. mock-as-function APPROVE / TXPARAM) replace
  EVM-immediate opcodes with view functions — gas costs differ.

These are not bugs. They are the explicit boundary of what this
experiment can prove. **Document them in any external writeup based
on this experiment.**

## 4. Iterate locally, NEVER deploy without local validation

Common newcomer mistake: deploy to testnet to "see if it works."
That wastes time and money. Correct order:

1. Run your tests against the local scaffold-evvm stack first
2. Fix failures locally (where \`npm run cli flush\` is free)
3. Only when local is solid, consider a testnet deployment
4. **NEVER deploy this package's contracts to mainnet** — the mocks
   are not production-safe by design. They are research scaffolding.

## 5. Graduate the mocks one at a time

When the contract-layer state machine holds up locally, the next
step is replacing mocks with real implementations:

- Mock ZK verifiers → real Groth16 / PLONK verifiers (requires
  trusted setup and your own circuit compilation)
- Mock Poseidon → vendored Solidity Poseidon2 (e.g., Aztec's port)
  or a Poseidon precompile if one ships
- Mock signature schemes → real precompiles (e.g., EIP-7951 for
  secp256r1) when they ship

**Replace one mock at a time** and re-run your test suite each time.
This isolates regressions cleanly.

## TL;DR

| Phase | What |
|-------|------|
| 0 | Read this file + \`justification.md\` |
| 1 | Read the EVVM docs relevant to your experiment |
| 2 | Drop into \`scaffold-evvm/experiments/\` and \`npm run wizard\` |
| 3 | Write tests in your own pipeline; iterate locally |
| 4 | Replace mocks one at a time when graduating |
| 5 | Testnet deployment only after local is solid |

## Links

- This package was generated by [EIPLab](https://github.com/0xOucan/eiplabv1)
- The skill behind it: https://github.com/EVVM-org/EIPskillevvmsandbox
- For questions about EVVM specifically: https://www.evvm.info
- The EIP under study: ${m.url}
`;
}

function main() {
  // Reset staging + output
  rmSync(STAGE_DIR, { recursive: true, force: true });
  rmSync(OUT_DIR, { recursive: true, force: true });
  mkdirSync(STAGE_DIR, { recursive: true });
  mkdirSync(OUT_DIR, { recursive: true });

  const slugs = readdirSync(CONTENT_DIR).filter((name) => {
    try {
      return statSync(join(CONTENT_DIR, name)).isDirectory();
    } catch {
      return false;
    }
  });

  for (const slug of slugs) {
    const src = join(CONTENT_DIR, slug);
    const dst = join(STAGE_DIR, slug);

    cpSync(src, dst, { recursive: true });

    // Read manifest, generate README
    const manifestPath = join(dst, "manifest.json");
    let manifest;
    try {
      manifest = JSON.parse(readFileSync(manifestPath, "utf-8"));
    } catch {
      console.warn(`[build-packages] no manifest at ${manifestPath}, skipping`);
      continue;
    }
    writeFileSync(join(dst, "README.md"), generateReadme(slug, manifest));
    writeFileSync(
      join(dst, "NEXT_STEPS.md"),
      generateNextSteps(slug, manifest),
    );

    // Zip it (quietly; -r recursive; -X strip extra attrs for reproducibility)
    const zipPath = join(OUT_DIR, `${slug}.zip`);
    try {
      execSync(`zip -rqX "${zipPath}" "${slug}"`, { cwd: STAGE_DIR });
      const size = statSync(zipPath).size;
      console.log(
        `[build-packages] ${slug}.zip → ${(size / 1024).toFixed(1)} KB`,
      );
    } catch (err) {
      console.error(`[build-packages] failed to zip ${slug}:`, err);
      process.exit(1);
    }
  }

  // Cleanup staging
  rmSync(STAGE_DIR, { recursive: true, force: true });

  console.log(`[build-packages] wrote ${slugs.length} packages to public/downloads/`);
}

main();
